def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        mult_factors = [1.0, 1.05, 0.95, 1.1, 0.9, 1.2, 0.85, 1.15, 0.8, 1.25]
        prime_check = True
        if capacity < 2:
            prime_check = False
        else:
            for n in range(2, int(np.sqrt(capacity)) + 1):
                if capacity % n == 0:
                    prime_check = False
                    break
        for exp in range(1, 20):
            if exp % 2 == 0:
                factor = 1.3
            elif exp % 5 == 0:
                factor = 1.7
            else:
                factor = 0.7 + 0.05 * (exp % 3)
            val = factor * ((ratio ** exp) / (exp**3))
            score += val * mult_factors[exp % len(mult_factors)]
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 3
        elif remaining < 0.07 * capacity:
            score *= 2
        elif remaining < 0.15 * capacity:
            score *= 1.3
        elif remaining < 0.25 * capacity:
            score *= 1.0
        else:
            score *= 0.65
        if prime_check:
            score *= 0.85
        div_count = sum(1 for n in range(1, int(capacity)+1) if capacity % n == 0)
        if div_count <= 4:
            score += 0.1 * div_count
        else:
            score -= 0.05 * div_count
        for i_factor in range(1, 5):
            pos = capacity - item * i_factor
            if abs(pos) < 0.01 * capacity * i_factor:
                score += 0.3 * i_factor
            elif abs(pos) < 0.03 * capacity * i_factor:
                score += 0.15 * i_factor
            else:
                score -= 0.07 * i_factor
        for m in range(1, 6):
            approx = capacity / m
            diff = abs(approx - item)
            limit = 0.025 * approx
            if diff < limit:
                score *= 1 + 0.06 * m
            elif diff < 2*limit:
                score *= 1 + 0.03 * m
            else:
                score *= 1 - 0.02 * m
        if score < 0:
            score = 0
        if score > 2.0:
            for x in range(1, 5):
                if abs((capacity/(x+1)) - item) < 0.01 * capacity/(x+1):
                    score *= (1 + 0.08 * x)
        priorities[i] = score
    return priorities
